-- ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~
-- Source: seeds/14_scale_threads.sql
-- ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~

-- =============================================================================
-- 14. SCALE THREADS (1M threads + translations)
-- Power-law author distribution: top 10% of lensers create ~60% of content.
-- =============================================================================

-- Step 1: Pre-materialize author assignments with power-law distribution
DROP TABLE IF EXISTS seed_profile_index;
CREATE UNLOGGED TABLE seed_profile_index AS
SELECT id, preferred_language,
  row_number() OVER (ORDER BY id) - 1 AS idx
FROM lensers.profiles
WHERE handle LIKE 'lenser_%'
ORDER BY id;

CREATE INDEX ON seed_profile_index (idx);

-- Step 2: Insert threads in batches of 50K
DO $$
DECLARE
  batch_start int;
  batch_size  int := 50000;
  total       int := 1000000;
  profile_cnt int;
BEGIN
  SELECT count(*) INTO profile_cnt FROM seed_profile_index;
  IF profile_cnt = 0 THEN
    RAISE EXCEPTION 'No seed profiles found. Run 12_scale_profiles.sql first.';
  END IF;

  FOR batch_start IN 0..total-1 BY batch_size LOOP
    RAISE NOTICE 'content.threads batch %/% ...', batch_start / batch_size + 1, total / batch_size;

    INSERT INTO content.threads (
      id, lenser_id, visibility, status,
      view_count, reply_count, created_at, updated_at
    )
    SELECT
      gen_random_uuid(),
      p.id,
      CASE
        WHEN rnd_vis < 0.85 THEN 'public'
        WHEN rnd_vis < 0.95 THEN 'community'
        ELSE 'private'
      END::"content"."visibility_enum",
      CASE
        WHEN rnd_stat < 0.90 THEN 'published'
        WHEN rnd_stat < 0.95 THEN 'draft'
        ELSE 'archived'
      END::"content"."content_status",
      (random() * 10000)::int,
      0,  -- backfilled later
      ca,
      ca + interval '1 hour'
    FROM (
      SELECT
        gs,
        -- Power-law: author_idx = floor(profile_count * pow(random(), 3))
        floor(profile_cnt * pow(random(), 3))::int AS author_idx,
        random() AS rnd_vis,
        random() AS rnd_stat,
        now() - (pow(random(), 1.5) * interval '365 days') AS ca
      FROM generate_series(batch_start, LEAST(batch_start + batch_size - 1, total - 1)) AS gs
    ) assignments
    JOIN seed_profile_index p ON p.idx = assignments.author_idx;
  END LOOP;
END $$;

-- Step 3: Original translations (one per thread, author's language)
INSERT INTO content.thread_translations (
  id, thread_id, language_code, title, content, is_original, created_at
)
SELECT
  gen_random_uuid(),
  t.id,
  COALESCE(p.preferred_language, 'en'),
  'Thread ' || row_number() OVER (ORDER BY t.created_at) || ': '
    || CASE (row_number() OVER (ORDER BY t.created_at) % 12)
      WHEN 0  THEN 'Exploring AI creativity'
      WHEN 1  THEN 'Building better prompts'
      WHEN 2  THEN 'Code review best practices'
      WHEN 3  THEN 'Machine learning insights'
      WHEN 4  THEN 'Community discussion'
      WHEN 5  THEN 'Creative writing challenge'
      WHEN 6  THEN 'Technology trends'
      WHEN 7  THEN 'Design thinking approach'
      WHEN 8  THEN 'Open source contribution'
      WHEN 9  THEN 'Data science workflow'
      WHEN 10 THEN 'Product development'
      ELSE         'General topic'
    END,
  'This is seed content for thread #' || row_number() OVER (ORDER BY t.created_at)
    || '. ' || repeat(
      CASE (row_number() OVER (ORDER BY t.created_at) % 5)
        WHEN 0 THEN 'Artificial intelligence continues to reshape how we think about creativity and problem solving. '
        WHEN 1 THEN 'The intersection of technology and human expression offers endless possibilities for innovation. '
        WHEN 2 THEN 'Community-driven development helps build more robust and inclusive software ecosystems. '
        WHEN 3 THEN 'Effective prompt engineering requires understanding both the model capabilities and the problem domain. '
        ELSE        'Collaboration across disciplines leads to breakthroughs that no single field could achieve alone. '
      END,
      2 + (random() * 4)::int
    ),
  true,
  t.created_at
FROM content.threads t
JOIN lensers.profiles p ON p.id = t.lenser_id
WHERE NOT EXISTS (
  SELECT 1 FROM content.thread_translations tt WHERE tt.thread_id = t.id
);

-- Step 4: Secondary translations for ~15% of public threads (English if original is not English, Turkish otherwise)
INSERT INTO content.thread_translations (
  id, thread_id, language_code, title, content, is_original, created_at
)
SELECT
  gen_random_uuid(),
  t.id,
  CASE WHEN p.preferred_language = 'en' THEN 'tr' ELSE 'en' END,
  '[Translated] Thread ' || row_number() OVER (ORDER BY t.created_at),
  '[Translated] Seed content for a multilingual thread. '
    || repeat('This translated paragraph provides additional linguistic diversity for feed testing. ', 3),
  false,
  t.created_at + interval '1 day'
FROM content.threads t
JOIN lensers.profiles p ON p.id = t.lenser_id
WHERE t.visibility = 'public'::"content"."visibility_enum"
  AND t.status = 'published'::"content"."content_status"
  AND random() < 0.15;


-- ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~
-- Source: seeds/15_scale_prompts.sql
-- ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~

-- =============================================================================
-- 15. SCALE PROMPTS (1M prompt_templates + translations)
-- Same power-law author distribution as threads.
-- =============================================================================

DO $$
DECLARE
  batch_start int;
  batch_size  int := 50000;
  total       int := 1000000;
  profile_cnt int;
BEGIN
  SELECT count(*) INTO profile_cnt FROM seed_profile_index;

  FOR batch_start IN 0..total-1 BY batch_size LOOP
    RAISE NOTICE 'content.prompt_templates batch %/% ...', batch_start / batch_size + 1, total / batch_size;

    INSERT INTO content.prompt_templates (
      id, lenser_id, visibility, status, created_at, updated_at
    )
    SELECT
      gen_random_uuid(),
      p.id,
      CASE
        WHEN rnd_vis < 0.85 THEN 'public'
        WHEN rnd_vis < 0.95 THEN 'community'
        ELSE 'private'
      END::"content"."visibility_enum",
      CASE
        WHEN rnd_stat < 0.90 THEN 'published'
        WHEN rnd_stat < 0.95 THEN 'draft'
        ELSE 'archived'
      END::"content"."content_status",
      ca,
      ca + interval '30 minutes'
    FROM (
      SELECT
        gs,
        floor(profile_cnt * pow(random(), 3))::int AS author_idx,
        random() AS rnd_vis,
        random() AS rnd_stat,
        now() - (pow(random(), 1.5) * interval '365 days') AS ca
      FROM generate_series(batch_start, LEAST(batch_start + batch_size - 1, total - 1)) AS gs
    ) assignments
    JOIN seed_profile_index p ON p.idx = assignments.author_idx;
  END LOOP;
END $$;

-- Original translations (one per prompt)
INSERT INTO content.prompt_translations (
  id, prompt_id, language_code, title, description, content, is_original, created_at
)
SELECT
  gen_random_uuid(),
  pt.id,
  COALESCE(p.preferred_language, 'en'),
  'Prompt ' || row_number() OVER (ORDER BY pt.created_at) || ': '
    || CASE (row_number() OVER (ORDER BY pt.created_at) % 10)
      WHEN 0 THEN 'Generate creative story'
      WHEN 1 THEN 'Code review assistant'
      WHEN 2 THEN 'Data analysis helper'
      WHEN 3 THEN 'Email draft writer'
      WHEN 4 THEN 'Technical documentation'
      WHEN 5 THEN 'Brainstorm ideas'
      WHEN 6 THEN 'Language translator'
      WHEN 7 THEN 'Summarize article'
      WHEN 8 THEN 'Debug code snippet'
      ELSE        'Custom task prompt'
    END,
  CASE WHEN random() < 0.7
    THEN 'A helpful prompt template for AI-assisted tasks. Use this to get started quickly.'
    ELSE NULL
  END,
  'You are a helpful assistant. ' || CASE (row_number() OVER (ORDER BY pt.created_at) % 6)
    WHEN 0 THEN 'Generate a creative short story based on the following theme: {{theme}}. Include vivid descriptions and compelling characters.'
    WHEN 1 THEN 'Review the following code for bugs, performance issues, and best practices: {{code}}. Provide specific suggestions for improvement.'
    WHEN 2 THEN 'Analyze the following dataset and provide key insights: {{data}}. Include trends, anomalies, and actionable recommendations.'
    WHEN 3 THEN 'Draft a professional email for the following situation: {{context}}. Maintain a {{tone}} tone and keep it concise.'
    WHEN 4 THEN 'Write technical documentation for the following API endpoint: {{endpoint}}. Include request/response examples and error handling.'
    ELSE        'Help me brainstorm ideas for: {{topic}}. Generate at least 5 creative and practical suggestions with brief explanations.'
  END,
  true,
  pt.created_at
FROM content.prompt_templates pt
JOIN lensers.profiles p ON p.id = pt.lenser_id
WHERE NOT EXISTS (
  SELECT 1 FROM content.prompt_translations ptt WHERE ptt.prompt_id = pt.id
);

-- Secondary translations for ~15% of public prompts
INSERT INTO content.prompt_translations (
  id, prompt_id, language_code, title, description, content, is_original, created_at
)
SELECT
  gen_random_uuid(),
  pt.id,
  CASE WHEN p.preferred_language = 'en' THEN 'tr' ELSE 'en' END,
  '[Translated] Prompt ' || row_number() OVER (ORDER BY pt.created_at),
  '[Translated] A prompt template for multilingual testing.',
  '[Translated] You are a helpful assistant. Help with the following task in a clear and organized manner.',
  false,
  pt.created_at + interval '1 day'
FROM content.prompt_templates pt
JOIN lensers.profiles p ON p.id = pt.lenser_id
WHERE pt.visibility = 'public'::"content"."visibility_enum"
  AND pt.status = 'published'::"content"."content_status"
  AND random() < 0.15;


-- ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~
-- Source: seeds/16_scale_tag_map.sql
-- ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~

-- =============================================================================
-- 16. SCALE TAG MAP (~3M tag associations)
-- Each thread/prompt gets 1-5 tags with power-law tag popularity.
-- =============================================================================

-- Pre-index tags for fast lookup
DROP TABLE IF EXISTS seed_tag_index;
CREATE UNLOGGED TABLE seed_tag_index AS
SELECT id AS tag_id, row_number() OVER (ORDER BY id) - 1 AS tidx
FROM content.tags
WHERE slug LIKE 'tag-%';

CREATE INDEX ON seed_tag_index (tidx);

-- Tag assignments for threads (~1.5M mappings, avg 1.5 tags per thread)
DO $$
DECLARE
  batch_start int;
  batch_size  int := 100000;
  total_threads int;
  tag_cnt int;
BEGIN
  SELECT count(*) INTO total_threads FROM content.threads;
  SELECT count(*) INTO tag_cnt FROM seed_tag_index;

  RAISE NOTICE 'Tagging % threads with % available tags...', total_threads, tag_cnt;

  -- Process threads in batches
  FOR batch_start IN 0..total_threads-1 BY batch_size LOOP
    RAISE NOTICE 'tag_map threads batch starting at %...', batch_start;

    INSERT INTO content.tag_map (id, entity_type, entity_id, tag_id, language_detected, created_at)
    SELECT DISTINCT ON (t.id, ti.tag_id)
      gen_random_uuid(),
      'thread'::"content"."entity_type_enum",
      t.id,
      ti.tag_id,
      NULL,
      t.created_at
    FROM (
      SELECT id, created_at, row_number() OVER (ORDER BY id) - 1 AS rn
      FROM content.threads
      ORDER BY id
      OFFSET batch_start LIMIT batch_size
    ) t
    CROSS JOIN LATERAL (
      -- 1-3 tags per thread, power-law tag selection
      SELECT (floor(tag_cnt * pow(random(), 2))::int) AS tidx
      FROM generate_series(1, 1 + (random() * 2)::int)
    ) tag_picks
    JOIN seed_tag_index ti ON ti.tidx = tag_picks.tidx
    ON CONFLICT DO NOTHING;
  END LOOP;
END $$;

-- Tag assignments for prompts (~1.5M mappings)
DO $$
DECLARE
  batch_start int;
  batch_size  int := 100000;
  total_prompts int;
  tag_cnt int;
BEGIN
  SELECT count(*) INTO total_prompts FROM content.prompt_templates;
  SELECT count(*) INTO tag_cnt FROM seed_tag_index;

  FOR batch_start IN 0..total_prompts-1 BY batch_size LOOP
    RAISE NOTICE 'tag_map prompts batch starting at %...', batch_start;

    INSERT INTO content.tag_map (id, entity_type, entity_id, tag_id, language_detected, created_at)
    SELECT DISTINCT ON (pt.id, ti.tag_id)
      gen_random_uuid(),
      'prompt_template'::"content"."entity_type_enum",
      pt.id,
      ti.tag_id,
      NULL,
      pt.created_at
    FROM (
      SELECT id, created_at, row_number() OVER (ORDER BY id) - 1 AS rn
      FROM content.prompt_templates
      ORDER BY id
      OFFSET batch_start LIMIT batch_size
    ) pt
    CROSS JOIN LATERAL (
      SELECT (floor(tag_cnt * pow(random(), 2))::int) AS tidx
      FROM generate_series(1, 1 + (random() * 2)::int)
    ) tag_picks
    JOIN seed_tag_index ti ON ti.tidx = tag_picks.tidx
    ON CONFLICT DO NOTHING;
  END LOOP;
END $$;


-- ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~
-- Source: seeds/17_scale_replies.sql
-- ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~

-- =============================================================================
-- 17. SCALE THREAD REPLIES (2M replies)
-- Distributed across public threads with power-law (popular threads get more).
-- =============================================================================

DO $$
DECLARE
  batch_start int;
  batch_size  int := 100000;
  total       int := 2000000;
  thread_cnt  int;
  profile_cnt int;
BEGIN
  SELECT count(*) INTO thread_cnt
  FROM content.threads
  WHERE visibility = 'public'::"content"."visibility_enum"
    AND status = 'published'::"content"."content_status";

  SELECT count(*) INTO profile_cnt FROM seed_profile_index;

  RAISE NOTICE 'Creating % replies across % public threads...', total, thread_cnt;

  FOR batch_start IN 0..total-1 BY batch_size LOOP
    RAISE NOTICE 'thread_replies batch %/% ...', batch_start / batch_size + 1, total / batch_size;

    INSERT INTO content.thread_replies (
      id, thread_id, parent_reply_id, lenser_id,
      content, status, created_at, updated_at
    )
    SELECT
      gen_random_uuid(),
      t.id,
      NULL,  -- top-level replies (no nesting for scale seed)
      p.id,
      'Reply #' || (batch_start + gs) || ': '
        || CASE (gs % 8)
          WHEN 0 THEN 'Great point! I agree with this perspective.'
          WHEN 1 THEN 'Interesting take. Have you considered the alternative approach?'
          WHEN 2 THEN 'Thanks for sharing. This helped me understand the concept better.'
          WHEN 3 THEN 'I disagree respectfully. Here is my reasoning...'
          WHEN 4 THEN 'Could you elaborate more on this? I find it fascinating.'
          WHEN 5 THEN 'This reminds me of a similar discussion from last week.'
          WHEN 6 THEN 'Well explained! The examples really make it clear.'
          ELSE        'Adding to the discussion: there are several nuances worth exploring here.'
        END,
      'published'::"content"."thread_reply_status",
      t.created_at + (random() * interval '30 days'),
      t.created_at + (random() * interval '30 days')
    FROM generate_series(0, LEAST(batch_size - 1, total - batch_start - 1)) AS gs
    -- Power-law thread selection: popular threads get more replies
    JOIN LATERAL (
      SELECT id, created_at
      FROM content.threads
      WHERE visibility = 'public'::"content"."visibility_enum"
        AND status = 'published'::"content"."content_status"
      ORDER BY view_count DESC
      OFFSET floor(thread_cnt * pow(random(), 2))::int
      LIMIT 1
    ) t ON true
    -- Random replier
    JOIN seed_profile_index p ON p.idx = floor(random() * profile_cnt)::int;
  END LOOP;
END $$;


-- ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~
-- Source: seeds/18_scale_follows.sql
-- ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~

-- =============================================================================
-- 18. SCALE FOLLOWS (2M lenser follows + 500K tag follows)
-- Power-law: popular lensers get more followers.
-- =============================================================================

-- Lenser follows (~2M)
DO $$
DECLARE
  batch_start int;
  batch_size  int := 100000;
  total       int := 2000000;
  profile_cnt int;
BEGIN
  SELECT count(*) INTO profile_cnt FROM seed_profile_index;

  FOR batch_start IN 0..total-1 BY batch_size LOOP
    RAISE NOTICE 'lensers.follows batch %/% ...', batch_start / batch_size + 1, total / batch_size;

    INSERT INTO lensers.follows (id, follower_id, following_id, created_at)
    SELECT
      gen_random_uuid(),
      follower.id,
      following.id,
      GREATEST(follower.created_at, following.created_at) + (random() * interval '30 days')
    FROM (
      -- Random follower
      SELECT p.id, (SELECT created_at FROM lensers.profiles WHERE id = p.id) AS created_at
      FROM seed_profile_index p
      WHERE p.idx = floor(random() * profile_cnt)::int
      LIMIT 1
    ) follower
    CROSS JOIN LATERAL (
      -- Power-law following: popular lensers followed more
      SELECT p.id, (SELECT created_at FROM lensers.profiles WHERE id = p.id) AS created_at
      FROM seed_profile_index p
      WHERE p.idx = floor(profile_cnt * pow(random(), 2))::int
        AND p.id <> follower.id
      LIMIT 1
    ) following
    CROSS JOIN generate_series(0, LEAST(batch_size - 1, total - batch_start - 1)) AS gs
    ON CONFLICT DO NOTHING;
  END LOOP;
END $$;

-- Tag follows (~500K, avg ~3.3 per lenser)
DO $$
DECLARE
  profile_cnt int;
  tag_cnt int;
BEGIN
  SELECT count(*) INTO profile_cnt FROM seed_profile_index;
  SELECT count(*) INTO tag_cnt FROM seed_tag_index;

  RAISE NOTICE 'Creating ~500K tag follows...';

  INSERT INTO lensers.tag_follows (id, lenser_id, tag_id, created_at)
  SELECT * FROM (
    SELECT
      gen_random_uuid(),
      p.id,
      ti.tag_id,
      now() - (random() * interval '180 days')
    FROM seed_profile_index p
    CROSS JOIN LATERAL (
      -- 1-7 tags per lenser, power-law tag popularity
      SELECT (floor(tag_cnt * pow(random(), 2))::int) AS tidx
      FROM generate_series(1, 1 + (random() * 6)::int)
    ) tag_picks
    JOIN seed_tag_index ti ON ti.tidx = tag_picks.tidx
    WHERE random() < 0.75  -- throttle to ~500K total
    LIMIT 500000
  ) sub
  ON CONFLICT DO NOTHING;
END $$;


-- ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~
-- Source: seeds/19_scale_reactions.sql
-- ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~

-- =============================================================================
-- 19. SCALE REACTIONS (5M thread + 3M prompt + 1M reply reactions)
-- Power-law: popular content gets disproportionately more reactions.
-- =============================================================================

-- ---------------------------------------------------------------------------
-- Thread reactions (~5M)
-- ---------------------------------------------------------------------------
DO $$
DECLARE
  batch_start int;
  batch_size  int := 250000;
  total       int := 5000000;
  thread_cnt  int;
  user_cnt    int;
BEGIN
  SELECT count(*) INTO thread_cnt
  FROM content.threads
  WHERE visibility = 'public'::"content"."visibility_enum"
    AND status = 'published'::"content"."content_status";

  SELECT count(*) INTO user_cnt
  FROM auth.users WHERE email LIKE '%@lenserfight.seed';

  RAISE NOTICE 'Creating % thread reactions across % threads...', total, thread_cnt;

  FOR batch_start IN 0..total-1 BY batch_size LOOP
    RAISE NOTICE 'thread_reactions batch %/% ...', batch_start / batch_size + 1, total / batch_size;

    INSERT INTO content.thread_reactions (id, thread_id, user_id, reaction, created_at)
    SELECT
      gen_random_uuid(),
      t.id,
      u.id,
      (ARRAY['like','love','clap','saved','copy','dislike'])[1 + floor(random() * 6)::int]::"content"."reaction_enum",
      t.created_at + (random() * interval '60 days')
    FROM generate_series(0, LEAST(batch_size - 1, total - batch_start - 1)) AS gs
    -- Power-law thread selection by view_count
    JOIN LATERAL (
      SELECT id, created_at FROM content.threads
      WHERE visibility = 'public'::"content"."visibility_enum"
        AND status = 'published'::"content"."content_status"
      ORDER BY view_count DESC
      OFFSET floor(thread_cnt * pow(random(), 3))::int
      LIMIT 1
    ) t ON true
    -- Random user
    JOIN LATERAL (
      SELECT id FROM auth.users
      WHERE email LIKE '%@lenserfight.seed'
      OFFSET floor(random() * user_cnt)::int
      LIMIT 1
    ) u ON true
    ON CONFLICT DO NOTHING;
  END LOOP;
END $$;

-- ---------------------------------------------------------------------------
-- Prompt reactions (~3M)
-- ---------------------------------------------------------------------------
DO $$
DECLARE
  batch_start int;
  batch_size  int := 250000;
  total       int := 3000000;
  prompt_cnt  int;
  user_cnt    int;
BEGIN
  SELECT count(*) INTO prompt_cnt
  FROM content.prompt_templates
  WHERE visibility = 'public'::"content"."visibility_enum"
    AND status = 'published'::"content"."content_status";

  SELECT count(*) INTO user_cnt
  FROM auth.users WHERE email LIKE '%@lenserfight.seed';

  RAISE NOTICE 'Creating % prompt reactions across % prompts...', total, prompt_cnt;

  FOR batch_start IN 0..total-1 BY batch_size LOOP
    RAISE NOTICE 'prompt_reactions batch %/% ...', batch_start / batch_size + 1, total / batch_size;

    INSERT INTO content.prompt_reactions (id, prompt_id, user_id, reaction, created_at)
    SELECT
      gen_random_uuid(),
      pt.id,
      u.id,
      (ARRAY['like','love','clap','saved','copy','dislike'])[1 + floor(random() * 6)::int]::"content"."reaction_enum",
      pt.created_at + (random() * interval '60 days')
    FROM generate_series(0, LEAST(batch_size - 1, total - batch_start - 1)) AS gs
    JOIN LATERAL (
      SELECT id, created_at FROM content.prompt_templates
      WHERE visibility = 'public'::"content"."visibility_enum"
        AND status = 'published'::"content"."content_status"
      OFFSET floor(prompt_cnt * pow(random(), 3))::int
      LIMIT 1
    ) pt ON true
    JOIN LATERAL (
      SELECT id FROM auth.users
      WHERE email LIKE '%@lenserfight.seed'
      OFFSET floor(random() * user_cnt)::int
      LIMIT 1
    ) u ON true
    ON CONFLICT DO NOTHING;
  END LOOP;
END $$;

-- ---------------------------------------------------------------------------
-- Thread reply reactions (~1M)
-- ---------------------------------------------------------------------------
DO $$
DECLARE
  batch_start int;
  batch_size  int := 250000;
  total       int := 1000000;
  reply_cnt   int;
  user_cnt    int;
BEGIN
  SELECT count(*) INTO reply_cnt FROM content.thread_replies;
  SELECT count(*) INTO user_cnt
  FROM auth.users WHERE email LIKE '%@lenserfight.seed';

  RAISE NOTICE 'Creating % reply reactions across % replies...', total, reply_cnt;

  FOR batch_start IN 0..total-1 BY batch_size LOOP
    RAISE NOTICE 'reply_reactions batch %/% ...', batch_start / batch_size + 1, total / batch_size;

    INSERT INTO content.thread_reply_reactions (id, reply_id, user_id, reaction, created_at)
    SELECT
      gen_random_uuid(),
      r.id,
      u.id,
      (ARRAY['like','love','clap','dislike'])[1 + floor(random() * 4)::int]::"content"."reaction_enum",
      r.created_at + (random() * interval '30 days')
    FROM generate_series(0, LEAST(batch_size - 1, total - batch_start - 1)) AS gs
    JOIN LATERAL (
      SELECT id, created_at FROM content.thread_replies
      OFFSET floor(reply_cnt * pow(random(), 2))::int
      LIMIT 1
    ) r ON true
    JOIN LATERAL (
      SELECT id FROM auth.users
      WHERE email LIKE '%@lenserfight.seed'
      OFFSET floor(random() * user_cnt)::int
      LIMIT 1
    ) u ON true
    ON CONFLICT DO NOTHING;
  END LOOP;
END $$;


-- ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~
-- Source: seeds/20_scale_xp.sql
-- ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~

-- =============================================================================
-- 20. SCALE XP TOTALS (150K entries)
-- Simulated XP distribution matching creator activity levels.
-- =============================================================================

INSERT INTO xp.totals (lenser_id, app_id, total_xp, updated_at)
SELECT
  p.id,
  '00000000-0000-0000-0000-000000000001'::uuid,
